const statsRaw = $('Fetch Daily Stats').first().json;
const balanceRaw = $('Fetch Balance').first().json;
const geoRaw = $('Fetch Geo Stats').first().json;

const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);
const balance = Number(balanceRaw?.data?.balance || balanceRaw?.balance || 0);
const geoStats = geoRaw?.data?.result?.data || geoRaw?.data || (Array.isArray(geoRaw) ? geoRaw : []);

let totalSpend = 0, totalRevenue = 0, totalClicks = 0, totalShows = 0;
const adPerformance = [];

if (Array.isArray(stats)) {
  stats.forEach(s => {
    const spend = s.money || 0;
    const revenue = s.postbacks_confirmed_money || 0;
    const clicks = s.clicks_count || 0;
    const shows = s.shows_count || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;

    totalSpend += spend;
    totalRevenue += revenue;
    totalClicks += clicks;
    totalShows += shows;

    adPerformance.push({ ad_id: s.ad_id, spend, revenue, roi, clicks });
  });
}

adPerformance.sort((a, b) => b.roi - a.roi);

const totalRoi = totalSpend > 0 ? ((totalRevenue - totalSpend) / totalSpend * 100) : 0;
const totalProfit = totalRevenue - totalSpend;
const top5 = adPerformance.filter(a => a.roi > 0).slice(0, 5);
const worst5 = adPerformance.filter(a => a.roi < 0 && a.spend > 0).slice(-5).reverse();
const activeAds = adPerformance.filter(a => a.clicks > 0).length;

const geoBreakdown = [];
if (Array.isArray(geoStats)) {
  geoStats.forEach(g => {
    const spend = g.money || 0;
    const revenue = g.postbacks_confirmed_money || 0;
    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    geoBreakdown.push({ country: g.country_code, spend, revenue, roi: Math.round(roi) });
  });
  geoBreakdown.sort((a, b) => b.roi - a.roi);
}

// Build report text
const date = $now.toFormat('dd.MM.yyyy');
const profitSign = totalProfit >= 0 ? '+' : '';

let msg = `DAILY REPORT ${date}\n`;
msg += `\nBalance: $${balance.toFixed(2)}`;
msg += `\nSpend: $${totalSpend.toFixed(2)} | Revenue: $${totalRevenue.toFixed(2)}`;
msg += `\nProfit: ${profitSign}$${totalProfit.toFixed(2)} | ROI: ${totalRoi.toFixed(1)}%`;
msg += `\nClicks: ${totalClicks} | Shows: ${totalShows} | Ads: ${activeAds}`;

if (top5.length > 0) {
  msg += `\n\nTOP ${top5.length}:`;
  top5.forEach(a => {
    msg += `\n  #${a.ad_id}: ROI ${a.roi.toFixed(1)}% profit $${(a.revenue - a.spend).toFixed(2)}`;
  });
}

if (worst5.length > 0) {
  msg += `\n\nWORST ${worst5.length}:`;
  worst5.forEach(a => {
    msg += `\n  #${a.ad_id}: ROI ${a.roi.toFixed(1)}% loss $${(a.spend - a.revenue).toFixed(2)}`;
  });
}

if (geoBreakdown.length > 0) {
  msg += `\n\nGEO:`;
  geoBreakdown.slice(0, 10).forEach(g => {
    msg += `\n  ${g.country}: ROI ${g.roi}% spend $${g.spend.toFixed(2)}`;
  });
}

return [{
  json: {
    date: $now.toFormat('yyyy-MM-dd'),
    balance: Math.round(balance * 100) / 100,
    total_spend: Math.round(totalSpend * 100) / 100,
    total_revenue: Math.round(totalRevenue * 100) / 100,
    total_profit: Math.round(totalProfit * 100) / 100,
    total_roi: Math.round(totalRoi * 100) / 100,
    report_text: msg
  }
}];
